using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<Person> directly, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"TryGetTypeInfo<Person> → found ({found!.Type.Name})");
}

// Now try a type whose metadata is NOT available.
// A source-gen-only options instance has no resolver for arbitrary types.
var limited = new JsonSerializerOptions { TypeInfoResolver = new EmptyResolver() };

if (limited.TryGetTypeInfo<Person>(out _))
{
    Console.WriteLine("TryGetTypeInfo<Person> on limited → found (unexpected)");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> on limited → not available (no exception!)");
}

// --- types -----------------------------------------------------------

public record Person(string Name, int Age);

/// A resolver that deliberately resolves nothing.
file sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

